import{_ as d,o as r,c as o,a2 as n}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"1966年致合伙人信","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1965年/翻译.md","filePath":"01_letters/1965年/翻译.md"}'),s={name:"01_letters/1965年/翻译.md"};function p(a,t,e,g,l,h){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="_1966年致合伙人信" tabindex="-1">1966年致合伙人信 <a class="header-anchor" href="#_1966年致合伙人信" aria-label="Permalink to &quot;1966年致合伙人信&quot;">​</a></h1><p><strong>发件人：沃伦·E·巴菲特</strong></p><p><strong>日期：1966年1月20日</strong></p><p><strong>致1966年各位合伙人：</strong></p><p>随信附上：</p><ol><li><p>1966年出资承诺书一式两份，一份由您留存，一份寄回给我们。您可在<strong>12月31日午夜前</strong>修改承诺书内容，请尽早寄回；如需变更，通过信件或电话告知即可。出资承诺书于12月31日最终生效。每年1月第一周，我都会接到不少电话，有人希望在1月1日追加资金——<strong>这是不允许的</strong>。</p></li><li><p>我们备受欢迎的《合伙基本规则》副本。我们必须在规则所列事项上达成共识。若您持有不同观点——当然，您的观点或许更优——但您不应继续留在本合伙基金。请特别留意<strong>第七条规则</strong>，该条款为今年新增，反映了我长期以来态度的适度转变。它采用了极为非传统（但在我看来适用于本基金运作且逻辑自洽）的方式，因此特意提请您注意。</p></li></ol><p>所有提款将于<strong>1月5日</strong>支付，您可提取100美元至全部权益的任意金额。同理，追加资金金额不限，需在<strong>1月10日前</strong>到账。若您处置资产，此举可让您在1966年完成交易，便于税务筹划。11月到账的追加资金视为预付款，按<strong>6%年利率</strong>计息至年末；12月到账的追加资金不计息。</p><p>本合伙基金持有<strong>伯克希尔·哈撒韦公司</strong>的控股权，该公司为上市证券。正如我年中信件所述，评估企业控股权价值时，<strong>资产价值与盈利能力</strong>是核心因素；而少数股权估值依赖的市场价格，对控股权估值几乎无意义。年末我们将按<strong>流动资产净值与账面价值的中间值</strong>评估伯克希尔持仓。鉴于公司应收账款与存货的特性，该估值方式相当于流动资产按全额计价、固定资产按半价计价。我认为这一估值对新入伙与退出的合伙人均公平，可能高于或低于当时市价。</p><p>撰写此信时，基金运作态势良好，我们跑赢道琼斯指数的幅度远超平均水平；即便用净利润这类原始标准衡量，业绩也能让那些保守的合伙人满意。当然，年末前业绩仍可能大幅变动。</p><p>如有任何疑问，可致电或致信<strong>约翰·哈丁</strong>，他负责为合伙人答疑解惑。税务情况与8月信件所述大致一致，若需约翰为您核算，他乐意效劳。</p><p>此致</p><p>沃伦·E·巴菲特</p><p><strong>附言：</strong> 我们继续执行“最晚寄回承诺书无奖励”政策，尽早寄回能方便我们工作。若您后续（1月1日前）需修改，致电即可，我们会为您调整。</p><hr><h2 id="_1965年业绩表现" tabindex="-1">1965年业绩表现 <a class="header-anchor" href="#_1965年业绩表现" aria-label="Permalink to &quot;1965年业绩表现&quot;">​</a></h2><p>1965年，我们的“脱贫之战”大获成功。</p><p>确切来说，年末我们的资产增加了<strong>12,304,060美元</strong>，变得更富裕了。</p><p>去年年度信件“我们的目标”板块（请注意标题并非“我们的承诺”）中，我写道：我们力争<strong>每年跑赢道琼斯指数平均10个百分点</strong>（普通合伙人分成前），业绩波动幅度较大——熊市可能跑输道指10个百分点，行情向好时则能跑赢25个百分点。</p><p>事实很快证明，我作为预测者并非完美，第一年就超出了预期区间。1965年，我们创下基金史上跑赢道指的最大幅度：基金总收益<strong>47.2%</strong>，道琼斯指数总收益（含持股分红）<strong>14.2%</strong>。当然，没人喜欢因这种预测失误公开“打脸”，这种情况不太可能再发生。</p><p>下表汇总了历年道琼斯指数表现、基金普通合伙人分成前业绩、有限合伙人最终收益：</p><table tabindex="0"><thead><tr><th>年份</th><th>道琼斯指数总收益(1)</th><th>合伙基金业绩(2)</th><th>有限合伙人收益(3)</th></tr></thead><tbody><tr><td>1957</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>38.5%</td><td>40.9%</td><td>32.2%</td></tr><tr><td>1959</td><td>20.0%</td><td>25.9%</td><td>20.9%</td></tr><tr><td>1960</td><td>-6.2%</td><td>22.8%</td><td>18.6%</td></tr><tr><td>1961</td><td>22.4%</td><td>45.9%</td><td>35.9%</td></tr><tr><td>1962</td><td>-7.6%</td><td>13.9%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.6%</td><td>38.7%</td><td>30.5%</td></tr><tr><td>1964</td><td>18.7%</td><td>27.8%</td><td>22.3%</td></tr><tr><td>1965</td><td>14.2%</td><td>47.2%</td><td>36.9%</td></tr><tr><td>(1) 基于道指年度变动+持股年度分红计算，涵盖基金完整运营年度。</td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1961年为所有前身合伙基金全年合并业绩，扣除所有费用、未分配给合伙人及普通合伙人分成前数据。</p><p>(3) 1957-1961年按合伙协议扣除普通合伙人分成、有限合伙人月度提款前数据。</p><h3 id="累计-复利收益" tabindex="-1">累计/复利收益 <a class="header-anchor" href="#累计-复利收益" aria-label="Permalink to &quot;累计/复利收益&quot;">​</a></h3><table tabindex="0"><thead><tr><th>统计周期</th><th>道琼斯指数总收益</th><th>合伙基金业绩</th><th>有限合伙人收益</th></tr></thead><tbody><tr><td>1957年</td><td>-8.4%</td><td>10.4%</td><td>9.3%</td></tr><tr><td>1957-1958</td><td>26.9%</td><td>55.6%</td><td>44.5%</td></tr><tr><td>1957-1959</td><td>52.3%</td><td>95.9%</td><td>74.7%</td></tr><tr><td>1957-1960</td><td>42.9%</td><td>140.6%</td><td>107.2%</td></tr><tr><td>1957-1961</td><td>74.9%</td><td>251.0%</td><td>181.6%</td></tr><tr><td>1957-1962</td><td>61.6%</td><td>299.8%</td><td>215.1%</td></tr><tr><td>1957-1963</td><td>95.1%</td><td>454.5%</td><td>311.2%</td></tr><tr><td>1957-1964</td><td>131.3%</td><td>608.7%</td><td>402.9%</td></tr><tr><td>1957-1965</td><td>164.1%</td><td>943.2%</td><td>588.5%</td></tr><tr><td><strong>年化复利</strong></td><td><strong>11.4%</strong></td><td><strong>29.8%</strong></td><td><strong>23.9%</strong></td></tr><tr><td>去年业绩亮眼，大家自然会问：<strong>接下来我们如何再创佳绩？</strong></td><td></td><td></td><td></td></tr></tbody></table><p>投资行业的短板在于<strong>几乎没有惯性</strong>：1965年通用汽车占据美国新车注册量54%，凭借客户忠诚度、经销商能力、产能与品牌形象，1966年大概率仍能维持相近份额。但巴菲特合伙基金并非如此——每年开盘时，所有资产按市值计价，我们<strong>从零开始</strong>。1966年的新老合伙人，仅能有限受益于1964、1965年的努力，过往成功的方法与理念无法直接复制到未来。</p><p>长期来看，我仍希望达成去年信件“我们的目标”中所述的业绩（副本仍可提供）。但如果有人认为1965年的业绩能频繁复制，恐怕和每周观测哈雷彗星的人一样不切实际。未来我们<strong>必然会遭遇亏损年份、跑输道指的年份</strong>，但我依旧相信，我们能长期跑赢道指。若这一预期发生变化，我会第一时间告知各位。</p><hr><h2 id="与投资公司对比" tabindex="-1">与投资公司对比 <a class="header-anchor" href="#与投资公司对比" aria-label="Permalink to &quot;与投资公司对比&quot;">​</a></h2><p>我们定期将业绩与<strong>两家最大的股票型开放式基金</strong>、<strong>两家最大的多元化封闭式基金</strong>对比。这四家公司——马萨诸塞投资者信托、投资者股票基金、三大陆公司、雷曼公司，管理规模超50亿美元，股东约60万人，堪称350亿美元投资公司行业的典型代表。在我看来，它们的业绩与绝大多数大型投资顾问机构基本持平。</p><p>对比数据旨在说明：<strong>道琼斯指数并非容易超越的业绩基准</strong>。这四家公司的投顾团队每年收取约1000万美元费用，却仅取得略低于道指（非管理型指数）的业绩。</p><h3 id="年度收益对比" tabindex="-1">年度收益对比 <a class="header-anchor" href="#年度收益对比" aria-label="Permalink to &quot;年度收益对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>马萨诸塞投资者信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>三大陆公司(2)</th><th>道琼斯指数</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1958</td><td>42.7%</td><td>47.5%</td><td>40.8%</td><td>33.2%</td><td>38.5%</td><td>32.2%</td></tr><tr><td>1959</td><td>9.0%</td><td>10.3%</td><td>8.1%</td><td>8.4%</td><td>20.0%</td><td>20.9%</td></tr><tr><td>1960</td><td>-1.0%</td><td>-0.6%</td><td>2.5%</td><td>2.8%</td><td>-6.2%</td><td>18.6%</td></tr><tr><td>1961</td><td>25.6%</td><td>24.9%</td><td>23.6%</td><td>22.5%</td><td>22.4%</td><td>35.9%</td></tr><tr><td>1962</td><td>-9.8%</td><td>-13.4%</td><td>-14.4%</td><td>-10.0%</td><td>-7.6%</td><td>11.9%</td></tr><tr><td>1963</td><td>20.0%</td><td>16.5%</td><td>23.7%</td><td>18.3%</td><td>20.6%</td><td>30.5%</td></tr><tr><td>1964</td><td>15.9%</td><td>14.3%</td><td>13.6%</td><td>12.6%</td><td>18.7%</td><td>22.3%</td></tr><tr><td>1965</td><td>10.2%</td><td>9.8%</td><td>19.0%</td><td>10.7%</td><td>14.2%</td><td>36.9%</td></tr><tr><td>(1) 按资产净值变动+年度持有人分红计算。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>(2) 1957-1964年数据来自1965年《穆迪银行与金融手册》，1965年为估算值。</p><h3 id="复利收益对比" tabindex="-1">复利收益对比 <a class="header-anchor" href="#复利收益对比" aria-label="Permalink to &quot;复利收益对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>统计周期</th><th>马萨诸塞投资者信托(1)</th><th>投资者股票基金(1)</th><th>雷曼公司(2)</th><th>三大陆公司(2)</th><th>道琼斯指数</th><th>有限合伙人</th></tr></thead><tbody><tr><td>1957年</td><td>-11.4%</td><td>-12.4%</td><td>-11.4%</td><td>-2.4%</td><td>-8.4%</td><td>9.3%</td></tr><tr><td>1957-1958</td><td>26.4%</td><td>29.2%</td><td>24.7%</td><td>30.0%</td><td>26.9%</td><td>44.5%</td></tr><tr><td>1957-1959</td><td>37.8%</td><td>42.5%</td><td>34.8%</td><td>40.9%</td><td>52.3%</td><td>74.7%</td></tr><tr><td>1957-1960</td><td>36.4%</td><td>41.6%</td><td>38.2%</td><td>44.8%</td><td>42.9%</td><td>107.2%</td></tr><tr><td>1957-1961</td><td>71.3%</td><td>76.9%</td><td>70.8%</td><td>77.4%</td><td>74.9%</td><td>181.6%</td></tr><tr><td>1957-1962</td><td>54.5%</td><td>53.2%</td><td>46.2%</td><td>59.7%</td><td>61.6%</td><td>215.1%</td></tr><tr><td>1957-1963</td><td>85.4%</td><td>78.5%</td><td>80.8%</td><td>88.9%</td><td>94.9%</td><td>311.2%</td></tr><tr><td>1957-1964</td><td>114.9%</td><td>104.0%</td><td>105.4%</td><td>112.7%</td><td>131.3%</td><td>402.9%</td></tr><tr><td>1957-1965</td><td>136.8%</td><td>124.0%</td><td>145.3%</td><td>138.4%</td><td>164.1%</td><td>588.5%</td></tr><tr><td><strong>年化复利</strong></td><td><strong>10.1%</strong></td><td><strong>9.4%</strong></td><td><strong>10.5%</strong></td><td><strong>10.1%</strong></td><td><strong>11.4%</strong></td><td><strong>23.9%</strong></td></tr><tr><td>诸多顶级投资顾问机构（管理规模达数十亿美元）会发行基金，既服务中小客户，也作为对外展示的“橱窗”，其业绩与上述四家基金大致相当。</td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>我坚信<strong>业绩衡量的重要性</strong>。上述投顾机构时刻用数据衡量工作：研究市场份额、利润率、资本回报率等，决策完全围绕量化指标。他们自然也会统计新业务拓展与顾问业务的盈利情况。</p><p>那么，<strong>衡量投资决策本身</strong>难道不是最核心的事吗？我并非认为自己衡量业绩的标准适用于所有基金经理，但我确信：任何代人理财的人，都应有明确的业绩衡量标准，且管理者与委托人需清晰理解标准的合理性、考核周期等。</p><p>弗兰克·布洛克在1965年11-12月《金融分析师期刊》中说得极好：</p><p>“投资业绩衡量的相关文献存在巨大空白。若投资机构追求最优业绩，严谨衡量业绩本应是常态。即便客户未主动要求，出于职业自尊，我们也应客观评估投资建议的质量——这离不开精准的业绩结果。掌握结果后，才能分析优势与短板。我们批评企业管理层不用工具追踪经营状况，同样，我们也没有理由不用工具评估自身的理财能力。遗憾的是，多数投资机构并未将业绩衡量系统纳入数据流程，有些机构甚至不愿知晓自身业绩优劣。”</p><p>坦白说，我坚持统一业绩衡量标准，有几个私心：</p><ol><li><p>我享受超越基准的感觉，正如凯西·施滕格尔所言：“告诉我一个输得起的人，我会告诉你他就是个输家。”</p></li><li><p>我确保自己只因“跑输道指”被问责，而非“年度亏损”。合伙人用正确标准评判，我才能更好地工作。</p></li><li><p>提前设定衡量标准，能确保业绩平庸时我们及时退出，不让过往成功蒙蔽对当下的判断，减少为糟糕业绩找借口的可能。</p></li></ol><p>这种“自虐式”的衡量方式看似无优势，但我观察到：这套评估体系能让很多投资与实业机构受益良多。</p><p>因此，若您在评估投资机构（或自己），请先制定标准、执行标准、解读结果。若您不认可我们的标准（<strong>至少以三年周期对标道指</strong>），则不应加入本基金；若认可，只要我们长期跑赢道指，就应坦然面对短期亏损年份。</p><hr><h2 id="复利的烦恼" tabindex="-1">复利的烦恼 <a class="header-anchor" href="#复利的烦恼" aria-label="Permalink to &quot;复利的烦恼&quot;">​</a></h2><p>往年写到这里，我会花点篇幅纠正过去四五百年的历史谬误，顺便展示复利的惊人力量，专栏名为《复利的乐趣》。眼尖的人会发现，今年标题略有变化。</p><p>可观的复利增速+大量新增资金，让我们今年初始资金达到<strong>4364.5万美元</strong>。过去我多次提出：<strong>资金规模扩大是否会损害投资业绩？</strong> 每次我都给出否定答案，并承诺若观点改变会立即告知。</p><p>截至目前，我认为规模扩大并未影响运作。事实上，过去几年我们的业绩，反而比小规模运作时更好——这得益于几笔规模适中的优质投资：对基金而言足够重要，又便于操作。</p><p>但现在我认为：<strong>规模继续扩大，很可能对未来业绩弊大于利</strong>。这一判断并非绝对，市场与商业环境多变，最优规模也会随之浮动。过去短期来看，我偶尔觉得规模小些更好，但更多时候觉得规模大更有利。</p><p>尽管如此，就当前环境而言，<strong>规模过大大概率会损害合伙人的收益</strong>（即便对我个人收益未必如此）。</p><p>因此，除非环境变化（新增资金能提升业绩），或新合伙人能带来资金以外的价值，否则我<strong>不再接受新合伙人加入</strong>巴菲特合伙基金。</p><p>为确保规则有效，我将一视同仁——我已告知苏珊，若我们再添孩子，由她为孩子找其他合伙基金。</p><p>考虑到现有合伙人的提款（如缴税）可能与追加资金持平，且规模扩大对业绩的负面影响较为温和，我目前<strong>不限制现有合伙人追加资金</strong>。</p><p>学医的朋友可能会觉得，这段文字足以证明“高效抗甲状腺药物”已问世。</p><hr><h2 id="业务投资方向" tabindex="-1">业务投资方向 <a class="header-anchor" href="#业务投资方向" aria-label="Permalink to &quot;业务投资方向&quot;">​</a></h2><p>去年我介绍了我们的四大投资类别，今年不再赘述，仅更新最新情况，帮大家理解各类别的优劣。</p><h3 id="_1-套利类-workout" tabindex="-1">1. 套利类（Workout） <a class="header-anchor" href="#_1-套利类-workout" aria-label="Permalink to &quot;1. 套利类（Workout）&quot;">​</a></h3><p>套利业务变得极不稳定，全年平均仅投入约600万美元，涉及标的极少。尽管该板块盈利约141万美元，<strong>平均资金回报率23.5%</strong>（全权益计算，实际使用杠杆后回报率更高），但超一半收益来自单一标的。在当前环境下，我认为该板块难以持续为大资金提供可观回报。不过我们仍会密切关注重大机会，少量参与优质小机会。</p><h3 id="_2-普通股-私人所有者视角-generals-private-owner-basis" tabindex="-1">2. 普通股-私人所有者视角（Generals-Private Owner Basis） <a class="header-anchor" href="#_2-普通股-私人所有者视角-generals-private-owner-basis" aria-label="Permalink to &quot;2. 普通股-私人所有者视角（Generals-Private Owner Basis）&quot;">​</a></h3><p>1965年该板块表现极佳。随着道指上涨，机会逐渐减少，但出现的机会往往意义重大。去年初我提到，我们是该板块三家公司的最大股东。1964年末最大持仓在1965年通过要约出售，实现<strong>税前收益318.8万美元</strong>；1964年末该持仓未实现增值45.1万美元，因此1965年实际经济收益为273.7万美元（税收全部计入1965年）。这说明：<strong>年度税前收益与实际经济收益无必然关联</strong>。</p><p>该板块的核心理念：私人所有者愿意为企业控制权支付的价格，远高于散户为小额股权支付的价格。这在证券市场长期普遍存在，即便仅跟随市场波动也能获利，偶尔还能因企业重组等行为获得巨额收益。</p><h3 id="_3-控股类-control" tabindex="-1">3. 控股类（Control） <a class="header-anchor" href="#_3-控股类-control" aria-label="Permalink to &quot;3. 控股类（Control）&quot;">​</a></h3><p>本板块新增一员——<strong>伯克希尔·哈撒韦</strong>，从“私人所有者视角”板块转入。我们自1962年11月开始买入伯克希尔，逻辑与上述标的一致。不同的是，我们最终买入足够股份，<strong>取得了公司控股权</strong>，而非在市场出售或卖给第三方。</p><p>1962年我们首次以<strong>7.60美元/股</strong>买入伯克希尔，股价低迷源于旧管理层关闭过时纺织厂产生的大额亏损（旧管理层对行业变化反应迟缓）。战后公司持续衰退，1948年巅峰期税前盈利2950万美元，员工1.1万人，拥有11家工厂。</p><p>1965年春取得控股权时，伯克希尔仅剩2家工厂、约2300名员工。令人惊喜的是，现有团队极为优秀，我们无需外聘管理人员。我们的平均持仓成本为<strong>14.86美元/股</strong>（1965年初大幅加仓），而1965年12月31日，公司<strong>仅净营运资金就达19美元/股</strong>（未计厂房设备价值）。</p><p>持有伯克希尔令人安心。纺织行业景气度决定公司盈利能力，但我们有幸拥有<strong>肯·蔡斯</strong>领衔的一流管理团队，各部门销售负责人也是行业顶尖。</p><p>伯克希尔或许无法像施乐、仙童相机、国家视频等高成长公司那般暴利，但它是稳健的底仓资产。正如我加州的哲学家朋友所说：“饮食既要奶油泡芙，也要燕麦粥。”</p><p>由于我们持有控股权，伯克希尔按<strong>企业价值</strong>估值，而非上市证券市值。即便股价上涨5美元，对基金无意义——我们不会出售；下跌5美元也无关紧要，持仓价值由企业本身价值决定。我对估值没有“神启”，仅基于资产、盈利能力、行业格局、竞争地位等做保守评估。按此估值我们不会卖出，年末组合中其他资产我们也不会卖出，否则早已变现。</p><h3 id="_4-普通股-相对低估类-generals-relatively-undervalued" tabindex="-1">4. 普通股-相对低估类（Generals-Relatively Undervalued） <a class="header-anchor" href="#_4-普通股-相对低估类-generals-relatively-undervalued" aria-label="Permalink to &quot;4. 普通股-相对低估类（Generals-Relatively Undervalued）&quot;">​</a></h3><p>随着其他板块机会减少，该板块重要性逐步提升。</p><p>坦白说，该板块的操作比其他三类更“虚”，而我并非务虚的人。因此我认为该板块的业绩不够扎实，对未来预测的参考价值更低。尽管如此，1965年该板块表现出色，部分得益于去年提到的<strong>降风险、提收益</strong>操作手法——该手法每年都能降低风险，1965年还显著提升了收益。需要说明的是，该板块业绩主要依赖两笔投资。</p><p>同时我也坦诚：1965年基金史上<strong>最糟糕的单笔投资</strong>，就出自该板块。</p><p>总体而言，1965年我们运气极佳。好点子不多，但质量很高（除上述一笔失败投资），且多笔投资的兑现周期提前。迈入1966年，我没有大量新点子，但仍有几笔潜在的大额优质机会，最终能否兑现取决于市场环境是否允许加仓。</p><p>总而言之，1965年我们<strong>兑现的收益远多于新增的布局</strong>。</p><hr><h2 id="分散投资" tabindex="-1">分散投资 <a class="header-anchor" href="#分散投资" aria-label="Permalink to &quot;分散投资&quot;">​</a></h2><p>去年我提到，绝大多数投资经理业绩平庸，主要源于五点：</p><ol><li><p>集体决策——我认为多方参与的团队决策，几乎不可能做出卓越的投资管理；</p></li><li><p>跟风头部机构的策略与持仓；</p></li><li><p>机构体制：平庸即“安全”，独立决策的个人回报与风险不匹配；</p></li><li><p>非理性的分散投资；</p></li><li><p>惰性。</p></li></ol><p>今年11月的材料中，我特意提醒各位注意<strong>第七条新规则</strong>：</p><p><strong>7. 我们的分散程度远低于多数投资机构。若事实与逻辑极大概率正确、投资标的内在价值大幅变动概率极低，我们可将至多40%的净资产投入单一证券。</strong></p><p>我们的分散策略与几乎所有公开投资机构截然不同。坦白说，我巴不得找到50个优质机会，每个都能年化跑赢道指15个百分点，且互不相关——这样我只需每只配2%资金，就能稳稳实现目标。</p><p>但现实并非如此。</p><p>我们费尽心力，也只能找到极少数优质投资机会。这类机会的定义是：<strong>年化至少跑赢道指10个百分点</strong>。少数机会中，预期收益差异巨大。核心问题始终是：“排名第一的机会，该配多少资金？第八的呢？”</p><p>这取决于两点：</p><ol><li><p>第一名与第八名的<strong>数学预期收益差距</strong>；</p></li><li><p>第一名大幅跑输道指的<strong>概率</strong>。</p></li></ol><p>两只数学预期相同的证券，若一只跑输道指15个百分点的概率为5%，另一只为1%，前者就不适合重仓。</p><p>上述逻辑看似精准，实则不然。我们的工作是<strong>核实事实，结合经验与理性形成预期</strong>，过程难免模糊、受情绪影响，但这就是投资的本质。多年投资决策的结果，会证明你的判断能力——无论你是否意识到自己在计算。我相信，清晰认知自己的思考路径，投资者会更具优势。</p><p>我可以明确保证：若追求优秀业绩，持有100只股票的组合（无论管理1000美元还是10亿美元）<strong>完全不符合逻辑</strong>。加入第100只股票，对组合波动的降低作用，远不及它拉低整体预期收益的负面影响。</p><p>即便研究过标的价值，持有上百只股票的投资者，我称之为**“诺亚式投资法”**——万物成双。诺亚遵循生物学法则，但这些投资者违背了数学原理。（我只学过平面几何，但除一人外，我谨慎筛选掉了基金中的数学家。）</p><p>他人非理性分散，不代表我们正确。我们必须从自身目标出发，论证合理的分散策略。</p><p>最优组合取决于：可选机会的预期收益、可承受的业绩波动幅度。</p><p>选择标的越多，年度业绩波动越小，但<strong>预期收益也越低</strong>（假设标的预期不同）。</p><p>为了长期更优业绩，我愿意<strong>放弃年度业绩的平稳性</strong>（业绩指相对道指的表现）。简单说：我愿意<strong>高度集中</strong>于自认最优的机会，即便这会导致偶尔大幅亏损——尽管业绩波动更大，但长期跑赢的幅度会更可观。</p><p>各位已看到实例：我们跑赢道指的幅度，从1958年的2.4个百分点，到1965年的33个百分点，波动远大于表格中的基金。我本可以降低波动，但也会牺牲整体业绩——即便如此，仍会远超行业平均。回顾过去，我甚至认为<strong>过去应该更集中</strong>。这也是新增第七条规则的原因。</p><p>再次强调：这一逻辑非传统（不代表对错，您需独立思考），若您不认同，本基金不适合您。</p><p>我们仅在<strong>极罕见情况</strong>下才会 single stock 持仓达40%，这种稀缺性正是重仓的前提。基金九年历史中，仅五六笔投资持仓超25%。这类机会必须满足：</p><ul><li><p>相对其他机会，<strong>显著更优</strong>；</p></li><li><p>定性/定量优势极强，<strong>永久亏损概率极低</strong>（短期股价波动除外）。</p></li></ul><p>确定单一投资的仓位上限时，我会确保：该投资（或相关组合）让组合跑输道指超10个百分点的概率<strong>极小</strong>。</p><p>目前我们有两笔持仓超25%：一笔是控股公司，另一笔是大型上市公司（我们不参与经营）。值得一提的是，1965年业绩<strong>几乎完全来自五笔投资</strong>，收益从80万美元到350万美元不等；而当年最小五笔普通投资，业绩平平无奇。</p><p>有趣的是，投资管理文献几乎没有关于<strong>最优分散投资推导</strong>的内容。所有教材都建议“充分分散”，但量化“充分”的人，从未解释过计算依据。</p><p>关于过度分散，我们引用著名学者比利·罗斯的话：</p><p><strong>“你有七十位佳丽的后宫，却对她们谁都不了解。”</strong></p><hr><h2 id="其他事项" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项" aria-label="Permalink to &quot;其他事项&quot;">​</a></h2><p>去年我们大胆扩张办公面积，新增227.25平方英尺，老合伙人都摇头。1965年1230.4万美元的运营利润证明，我们并未过度扩张。幸运的是，我们未签比例租金合约。目前运营极为顺畅，我能投入<strong>更高比例的时间思考投资</strong>，远超绝大多数资管从业者——这离不开优秀的团队与配合的合伙人。</p><p>约翰·哈丁全面负责行政工作，成果出色；比尔·斯科特持续深挖投资细节，显著提升净利润；贝丝·费汉、唐娜·沃尔特、伊丽莎白·哈农（11月入职）高效精准完成大量工作。</p><p>上述员工及其家属在基金的投资合计超<strong>60万美元</strong>；我与苏珊的投资达<strong>684.9936万美元</strong>，这是我们几乎全部净资产（仅保留1960年买入的本地公司Mid-Continent Tab Card股份，当时股东不足10人）。</p><p>此外，我的三位子女、母亲、两位姐妹、两位连襟、岳父、三位阿姨、两位叔叔、五位表亲、六位侄甥，直接或间接持有基金份额合计<strong>270.8233万美元</strong>。所以别想投票更改基金名称了。</p><p>皮特·马利克·米切尔会计师事务所一如既往出色完成审计与税务工作，今年还引入了计算机系统，我一度担心被抢了普通合伙人的位置，结果运行十分顺畅。</p><p>未来两周内，您将收到：</p><ol><li><p>税务说明信：包含1965年联邦个税申报所需的全部基金信息，此为唯一税务有效文件；</p></li><li><p>1965年审计报告：列明基金经营、财务状况及您的个人账户；</p></li><li><p>我签署的信件：列明1966年1月1日您的基金权益，与审计数据一致。</p></li></ol><p>若此信或年度内有任何疑问，请告知我。我难以预判所有问题，若有困惑，务必联系我们。例如去年我们收到合伙人的优秀建议，优化了个人账户对账展示。</p><p>我的下一封信约在<strong>7月15日</strong>，汇总上半年业绩。</p><p>此致</p><p>沃伦·E·巴菲特</p><p>巴菲特合伙有限公司</p><p>内布拉斯加州奥马哈市基维特广场610号</p>',119)])])}const u=d(s,[["render",p]]);export{b as __pageData,u as default};
